(function () {
  function ensureTelemetryLog() {
    const existing = window.appTelemetry && typeof window.appTelemetry === 'object' ? window.appTelemetry : {};
    if (!Array.isArray(existing.events)) {
      existing.events = [];
    }
    if (!Number.isFinite(existing.limit) || existing.limit <= 0) {
      existing.limit = 100;
    }

    if (typeof existing.record !== 'function') {
      existing.record = function (level, message, details) {
        const entry = {
          timestamp: new Date().toISOString(),
          level: String(level || 'info'),
          message: String(message || ''),
          details: details || null
        };
        this.events.push(entry);
        const overflow = this.events.length - this.limit;
        if (overflow > 0) {
          this.events.splice(0, overflow);
        }
        return entry;
      };
    }

    if (typeof existing.last !== 'function') {
      existing.last = function () {
        return this.events.length ? this.events[this.events.length - 1] : null;
      };
    }

    window.appTelemetry = existing;
    return existing;
  }

  function logTelemetry(level, message, details) {
    try {
      const telemetry = ensureTelemetryLog();
      if (telemetry && typeof telemetry.record === 'function') {
        return telemetry.record(level, message, details);
      }
    } catch (error) {
      // Ignore telemetry logging failures so notifications still work.
    }
    return null;
  }

  function createNotifyTools(options) {
    const settings = options || {};
    const toastContainer = settings.toastContainer;

    function showToast(message, variant, timeout) {
      const text = String(message || '').trim();
      if (!text) return;

      if (!toastContainer) {
        if (variant === 'error') console.error(text);
        else if (variant === 'warning') console.warn(text);
        else console.info(text);
        logTelemetry(variant, text, { toast: false });
        return;
      }

      const toast = document.createElement('div');
      toast.className = `toast toast-${variant}`;
      toast.setAttribute('role', 'status');
      toast.textContent = text;
      toastContainer.appendChild(toast);

      window.setTimeout(() => {
        toast.remove();
      }, Math.max(1200, timeout));

      logTelemetry(variant, text, { toast: true });
    }

    const notify = {
      success(message) {
        showToast(message, 'success', 2600);
      },
      info(message) {
        showToast(message, 'info', 2600);
      },
      warn(message) {
        showToast(message, 'warning', 3200);
      },
      error(message) {
        showToast(message, 'error', 3600);
      }
    };

    // Show an action toast with buttons. actions: [{id,label,primary}]
    // Returns a Promise resolving to the chosen action id, or null on timeout/dismiss.
    function actionToast(message, actions, options) {
      const ops = options || {};
      const timeout = Number(ops.timeout) || 10000;
      const act = Array.isArray(actions) ? actions.slice(0) : [{ id: 'ok', label: 'OK' }];

      return new Promise((resolve) => {
        if (!toastContainer) {
          // No DOM: fallback to prompt/confirm
          try {
            const accepted = window.confirm(String(message || ''));
            resolve(accepted ? (act[0] && act[0].id) || 'ok' : null);
            return;
          } catch (e) {
            resolve(null);
            return;
          }
        }

        const previousActive = document.activeElement;
        const toast = document.createElement('div');
        toast.className = 'toast toast-action';
        toast.setAttribute('role', 'status');

        const msg = document.createElement('div');
        msg.className = 'toast-message';
        msg.textContent = String(message || '');
        toast.appendChild(msg);

        const actionsBar = document.createElement('div');
        actionsBar.className = 'toast-actions';
        act.forEach((a, idx) => {
          const btn = document.createElement('button');
          btn.type = 'button';
          btn.className = 'toast-btn' + (a.primary ? ' toast-btn-primary' : '');
          btn.textContent = String(a.label || a.id || '');
          btn.addEventListener('click', function (ev) {
            cleanup();
            resolve(a.id);
          });
          actionsBar.appendChild(btn);
        });

        toast.appendChild(actionsBar);
        toastContainer.appendChild(toast);

        // Focus first action button
        const firstBtn = actionsBar.querySelector('button');
        if (firstBtn) firstBtn.focus();

        let dismissed = false;
        const removeToast = function () {
          if (dismissed) return;
          dismissed = true;
          try { toast.remove(); } catch (e) { /* ignore */ }
        };

        const timeoutId = window.setTimeout(() => {
          removeToast();
          try { if (previousActive && typeof previousActive.focus === 'function') previousActive.focus(); } catch (e) { /* ignore */ }
          resolve(null);
        }, timeout);

        function cleanup() {
          window.clearTimeout(timeoutId);
          removeToast();
          try { if (previousActive && typeof previousActive.focus === 'function') previousActive.focus(); } catch (e) { /* ignore */ }
        }
      });
    }

    function notifyFromError(err, fallbackMessage) {
      const msg = (err && (err.message || err.toString())) ? (err.message || String(err)) : (fallbackMessage || 'An error occurred');
      logTelemetry('error', msg, { error: err || null });
      if (notify && typeof notify.error === 'function') {
        notify.error(msg);
        return;
      }
      if (window && window.appNotify && typeof window.appNotify.error === 'function') {
        window.appNotify.error(msg);
        return;
      }
      console.error(msg);
    }

    return {
      showToast: showToast,
      notify: notify,
      action: actionToast,
      notifyFromError: notifyFromError
    };
  }

  window.createNotifyTools = createNotifyTools;
  window.appLogEvent = logTelemetry;
  window.appTelemetry = ensureTelemetryLog();
  // Expose a small global helper for modules that may run before notify is wired up.
  window.notifyFromError = function (err, fallback) {
    const msg = (err && (err.message || err.toString())) ? (err.message || String(err)) : (fallback || 'An error occurred');
    logTelemetry('error', msg, { error: err || null, fallback: fallback || null });
    if (window && window.createNotifyTools) {
      try {
        // Try to use the app-level notify if available
        const runtime = (window.appNotify && window.appNotify.error) ? window.appNotify : null;
        if (runtime && typeof runtime.error === 'function') {
          runtime.error(msg);
          return;
        }
      } catch (e) {
        // fall through
      }
    }
    try { console.error(msg); } catch (e) { /* noop */ }
  };
})();
